/**
 * Browser entry — wires F-001 through F-035 into a playable game.
 *
 * Top-level layout:
 *   1. Scene bootstrap (background, lights, playfield)
 *   2. Persistence (high score, settings)
 *   3. Audio system (settings-driven volume + muted)
 *   4. Run state (score, cooldown, queue, detector, controller, achievements)
 *   5. Visuals (launcher anchor, particle bursts, trajectory line)
 *   6. UI (score overlay, queue strip, power meter, pause badge,
 *      game-over overlay, tutorial)
 *   7. Input (slingshot, touch guard, keyboard aim)
 *   8. Game loop — pause-aware step, drain merges, evaluate game-over,
 *      render
 */

import { bootstrapScene } from "./scene/bootstrap.ts";
import { createEarth } from "./scene/earth.ts";
import { createStarfield } from "./scene/starfield.ts";
// cosmic-decorations (background planets + shooting stars) intentionally
// not mounted — backdrop is now minimalist deep space.
