const canvas = document.querySelector<HTMLCanvasElement>(
  '[data-testid="game-canvas"]',
);
if (!canvas) {
  throw new Error("[data-testid=game-canvas] is missing from index.html");
}
const main = document.querySelector("main");
if (!main) {
  throw new Error("<main> is missing from index.html");
}

// 1. Scene =================================================================
// F-094 — visualViewport API 가 있으면 실제 보이는 영역으로 초기화. 모바일
// 브라우저 chrome 이 펼쳐진 상태에서도 잘리지 않게.
const initialViewport = window.visualViewport
  ? { width: window.visualViewport.width, height: window.visualViewport.height }
  : { width: window.innerWidth, height: window.innerHeight };
const handles = bootstrapScene({
  canvas,
  width: initialViewport.width,
  height: initialViewport.height,
});
preloadAllPlanetTextures();

// F-041 — wider, slightly elevated framing for 3D depth. Camera tilts
// down ~12° so planets read as orbital bodies, not flat decals.
// Frame: pulled back enough that the bigger Earth (radius 4.6) on the
// right + the launch zone on the left both fit comfortably with breathing
// room. Slight elevation so the cartoon planet reads with depth.
handles.camera.position.set(0, 4, 34);
handles.camera.lookAt(0, 0, 0);
handles.camera.fov = 50;
handles.camera.updateProjectionMatrix();

// Sharper cel banding — more directional contrast, lower ambient
// floor. Pure-step gradient (no easing) plus this lighting balance
// produces a clear lit/shadow split on every body.
handles.lights.ambient.intensity = 0.40;
handles.lights.sun.intensity = 1.55;

// Beautiful rotating Earth on the right side. Visible gravity source +
// solid surface meteors collide with and stack on.
const EARTH_POSITION = { x: 14, y: 0, z: 0 };
const earth = createEarth({ position: EARTH_POSITION });
handles.scene.add(earth.group);
// (Earth uses MeshToonMaterial — lit by handles.lights.sun directly.)

// Visible ozone boundary — debris that drifts past this radius and
// settles there counts as a breach. Each breach deals tier-scaled
// damage to Earth's structural integrity; full collapse = game over.
// Offset slightly increased (4.2 → 4.8) to give the player a touch
// more buffer between Earth and the breach line.
const OZONE_RADIUS = earth.radius + 4.8;
const ozoneRing = createOzoneRing({
  earthRadius: earth.radius,
  ozoneRadius: OZONE_RADIUS,
});
ozoneRing.mesh.position.set(EARTH_POSITION.x, EARTH_POSITION.y, EARTH_POSITION.z);
handles.scene.add(ozoneRing.mesh);

// 달 — Earth 를 천천히 도는 궤도 장애물. 운석이 부딪히면 튕긴다.
const moon = createOrbitingMoon({
  center: EARTH_POSITION,
  initialAngle: Math.PI * 0.3,
});
handles.scene.add(moon.group);

// F-039 — instanced point starfield. Sits inside the gradient sphere.
const starfield = createStarfield();
handles.scene.add(starfield.object);

// (Background planets + shooting stars removed — F-052 simplified the
// backdrop. The flat cel-banded dome + 3D starfield carry the cosmic
// feel without busy decorations competing with the play action.)

// 2. Persistence ===========================================================
const highScoreStore = createHighScoreStore();
const settingsStore = createSettingsStore();
const leaderboard = createLeaderboard();

// Pre-resolve the online-mode flag so UI code constructed BEFORE the
// onlineStore is wired (e.g. game-over-overlay) can branch on it.
const onlineModeAvailable =
  Boolean(getSupabaseClient()) && Boolean(getScoreSigningKey());

// 2b. Locale — set before any UI component renders so first paint is in
// the player's language. Manual override (settings.locale) wins over the
// browser auto-detect.
setLocale(settingsStore.current().locale ?? detectLocale());

// 2c. Run start timestamp — used by score-submit to compute duration_ms.
const runStartedAt = { current: Date.now() };

// 3. Audio =================================================================
const audio = createAudioSystem({
  initialVolume: settingsStore.current().volume,
  initialMuted: settingsStore.current().muted,
});
settingsStore.subscribe((s) => {
  audio.setVolume(s.volume);
  audio.setMuted(s.muted);
});

// 4. Run state =============================================================
const score = new Score();
score.setHighScore(highScoreStore.load());

const cooldown = createCooldown();
const queue = createPlanetQueue({
  lookahead: 3,
  generator: defaultTierGenerator(),
});
// F-037: limit-line game-over no longer applies (no top-stack concept
// in the side-on Sun layout). Park the detector at an unreachable y so
// it never fires; F-040 introduces the ammo-based game over.
const detector = createGameOverDetector({
  limitLineY: 999,
});
const pause = createPauseController();
const achievements = createAchievementsRegistry();
// Ammo controller is retained for the achievement/daily-challenge code
// paths but is no longer a game-over trigger — the new rule is the
// ozone breach system below. We give it a very high cap so suika-style
// unlimited play is the effective UX.
const ammo = createAmmoController({ total: 9999 });
const combo = createComboTracker();
// Post-merge velocity stabilizer — keeps freshly-merged bodies from
// springing wildly upward when cannon-es resolves their spawn overlap.
const mergeSettle = createMergeSettle();
const ozone = createOzoneTracker({
  ozoneRadius: OZONE_RADIUS,
  // 100-point structural integrity — paired with tier-scaled damage so
  // bigger meteors drain Earth faster (default damageForTier).
});

// Orbit escape — far past the ozone, the meteor is effectively
// off-screen and counts as a separate "lost asset" event (not a
// boundary breach). Radius chosen so the launch origin (distance ~30
// from Earth) is comfortably inside, while truly off-screen flights
// still trip the detector.
const ESCAPE_RADIUS = 45;
const escape = createEscapeDetector({ escapeRadius: ESCAPE_RADIUS });
achievements.attachToScore(score);

// Gravity well centered on Earth — strong pull so meteors actually
// arc into the planet from across the playfield.
const sim = createSimulation({
  scene: handles.scene,
  well: {
    center: EARTH_POSITION,
    strength: 320,
    maxRadius: 80,
    minDistance: earth.radius + 0.5,
  },
});

// Add Earth's static body to the physics world so meteors collide with
// (and stack on) its surface rather than passing through.
sim.world.add(earth.body);
// Moon's kinematic body — meteors bounce off naturally via cannon.
sim.world.add(moon.body);
const runController = createRunController({
  sim,
  score,
  cooldown,
  queue,
  detector,
  reseedQueue: () => queue.reseed(defaultTierGenerator()),
});

// 5. Visuals ===============================================================
// Visible "next ammo" preview at the slingshot origin. Without this,
// players couldn't see what they were about to fire — the launch zone
// looked empty.
const LAUNCH_ORIGIN = { x: -16, y: 0, z: 0 };
const launcherPreview = createLauncherPreview({ origin: LAUNCH_ORIGIN });
handles.scene.add(launcherPreview.group);
const launcher = {
  origin: LAUNCH_ORIGIN,
  setNextTier: (tier: number): void => launcherPreview.setNextTier(tier),
  reload: (tier: number): void => launcherPreview.reload(tier),
  setPullOffset: (offset: { x: number; y: number }): void =>
    launcherPreview.setPullOffset(offset),
  setVisible: (visible: boolean): void => launcherPreview.setVisible(visible),
};
launcher.setNextTier(queue.peek()[0] ?? 0);

const particles = createParticleBurstSystem({ scene: handles.scene });
const trajectory = createTrajectoryLine({ scene: handles.scene });
const trails = createPlanetTrailSystem({ scene: handles.scene });

// Cel spark burst on every meteor-meteor contact — including
// cross-tier bounces where no merge happens. Gives the player a
// satisfying "thump" cue.
sim.collisions.onImpact((impact) => {
  // Skip merge-tier same-pair impacts: those already get the bigger
  // merge burst from the resolveMerges path. Spark is for everything
  // else — bounces, glances, large-vs-small contacts.
  if (impact.isMerge) return;
  const intensity = Math.min(1.5, 0.5 + impact.speed * 0.05);
  particles.spawnSpark({
    position: impact.point,
    color: impact.primary.tier.color,
    intensity,
  });
});

// Earth structural-stress reactions — each breach scales with the
// breaching meteor's tier (bigger tier = more stress + bigger FX).
ozone.subscribeBreach((breach) => {
  ozoneRing.flashBreach();
  breachWarning.flashBreach();
  // Camera kick scales with damage so heavy hits feel heavy.
  const kick = 0.5 + breach.damage * 0.04;
  cameraShake.kick(Math.min(1.6, kick));
  integrityMeter.punchLoss();
  const meteor = sim.planets.find((p) => p.id === breach.meteorId);
  if (meteor) {
    const sparkCount = 3 + Math.floor(breach.damage / 4);
    for (let i = 0; i < sparkCount; i += 1) {
      particles.spawnSpark({
        position: {
          x: meteor.body.position.x,
          y: meteor.body.position.y,
          z: meteor.body.position.z,
        },
        color: 0xff5b5b,
        intensity: Math.min(1.8, 0.9 + breach.damage * 0.04),
      });
    }
  }
  audio.play("gameover", { intensity: 0.4 });
});

// Pipe integrity ratio into Earth visuals — atmosphere color shifts
// + planet wobble intensifies as the world approaches collapse.
ozone.subscribeIntegrity((s) => {
  earth.setStress(s.current / s.max);
});

// 궤도 이탈 (orbit escape) — flash distinct banner + camera kick +
// small spark. The integrity hit is intentionally lighter than a
// breach since the meteor is GONE (no longer pressing on Earth).
escape.subscribe((event) => {
  breachWarning.flashEscape();
  cameraShake.kick(0.55);
  audio.play("gameover", { intensity: 0.25 });
  // Light cyan sparks at the last known meteor position.
  const meteor = sim.planets.find((p) => p.id === event.meteorId);
  if (meteor) {
    particles.spawnSpark({
      position: {
        x: meteor.body.position.x,
        y: meteor.body.position.y,
        z: meteor.body.position.z,
      },
      color: 0x6ec4ff,
      intensity: 1.0,
    });
  }
});

// Detect meteor → Moon contact and flash a silver spark — the moon is
// an obstacle so the player needs visual feedback when their shot
// glances off it.
moon.body.addEventListener("collide", (e: { body: { id: number } }) => {
  const meteor = sim.planets.find((p) => p.body.id === e.body.id);
  if (!meteor) return;
  const speed = meteor.body.velocity.length();
  if (speed < 0.8) return;
  particles.spawnSpark({
    position: {
      x: meteor.body.position.x,
      y: meteor.body.position.y,
      z: meteor.body.position.z,
    },
    color: 0xc0bcd0,
    intensity: Math.min(1.4, 0.7 + speed * 0.04),
  });
});

// Detect meteor → Earth contact directly off Earth's static body so we
// also flash a spark when a meteor lands on the planet surface.
earth.body.addEventListener("collide", (e: { body: { id: number } }) => {
  const meteor = sim.planets.find((p) => p.body.id === e.body.id);
  if (!meteor) return;
  const speed = meteor.body.velocity.length();
  if (speed < 1.5) return; // ignore gentle resting contacts
  particles.spawnSpark({
    position: {
      x: meteor.body.position.x,
      y: meteor.body.position.y,
      z: meteor.body.position.z,
    },
    color: meteor.tier.color,
    intensity: Math.min(1.5, 0.6 + speed * 0.04),
  });
});

// 6. UI ====================================================================
const scoreOverlay = attachScoreOverlay(score, main);
const integrityMeter = attachIntegrityMeter(ozone, main);
const queueStrip = createQueueStrip(queue, main);
const powerMeter = createPowerMeter(main);
const pauseBadge = attachPauseBadge(pause, main);
void attachAmmoOverlay; // legacy export retained for tests; HUD no longer mounts it
void integrityMeter;
let endlessMode = false;
// F-086 — track this run's max tier for leaderboard "도달 단계" display.
// Reset on restart; updated whenever a higher tier is forged.
let peakTierThisRun = 0;
const goalPill = attachGoalPill(main);
const tierLadderPanel = attachTierLadderPanel(main);
const gameOverOverlay = createGameOverOverlay(main, {
  onRestart: () => {
    trails.clear();
    runController.restart();
    detector.reset();
    ammo.reset();
    combo.reset();
    ozone.reset();
    endlessMode = false;
    peakTierThisRun = 0;
    mergeSettle.reset();
    escape.reset();
    goalPill.reset();
    tierLadderPanel.reset();
    launcher.setVisible(true);
    launcher.setPullOffset({ x: 0, y: 0 });
    launcher.setNextTier(queue.peek()[0] ?? 0);
    queueStrip.refresh();
    gameOverOverlay.hide();
    runStartedAt.current = Date.now();
  },
  onContinue: () => {
    // Victory acknowledged — keep the run going for high-score chasing.
    gameOverOverlay.hide();
    launcher.setVisible(true);
  },
  // F-076 — explicit submit entry. Wired only when online mode is
  // available. The button shows up on the run-end overlay so the user
  // can register any non-zero score, not just new personal bests.
  ...(onlineModeAvailable
    ? {
        onSubmit: () => {
          const snap = score.snapshot();
          if (snap.current <= 0) return;
          maybePromptSubmit(snap, endlessMode, true);
        },
      }
    : {}),
});

const comboBadge = attachComboBadge(combo, main);
const scorePopups = createScorePopupSystem({ host: main, camera: handles.camera });
const cameraShake = createCameraShake({ camera: handles.camera });
const breachWarning = createBreachWarning({ host: main, camera: handles.camera });
void comboBadge;

const tutorial = createTutorialController();
const tutorialOverlay = mountTutorialOverlay(main, tutorial, {
  // F-079 — freeze the sim while the user reads the tutorial; resume on
  // dismiss (next-end or skip) so play starts immediately.
  onShown: () => pause.pause(),
  onDismissed: () => pause.resume(),
});

// =========================================================================
// 4b. F-073 — Auth + global leaderboard wiring.
// =========================================================================
const supabaseClient = getSupabaseClient();
const signingKey = getScoreSigningKey();
const authController = createAuthController(supabaseClient);
// F-081 — hash cleanup moved INTO createAuthController so it fires
// AFTER supabase-js has consumed the callback hash. Calling it here
// (boot-time, before INITIAL_SESSION) raced with detectSessionInUrl
// and silently killed every new OAuth session.
const onlineStore =
  supabaseClient && signingKey
    ? createOnlineLeaderboardStore({
        client: supabaseClient,
        signingKey,
      })
    : null;

async function refreshLeaderboard(forceRefresh = false): Promise<void> {
  if (!onlineStore) {
    leaderboardPage.setStatus("offline");
    leaderboardPage.setRows([]);
    return;
  }
  leaderboardPage.setStatus("loading");
  try {
    const rows = await onlineStore.fetchTop(1000, { forceRefresh });
    leaderboardPage.setRows(rows);
    leaderboardPage.setStatus("online");
    const user = authController.getUser();
    if (user) {
      const userRow = await onlineStore.fetchUserRank(user.id, { forceRefresh });
      leaderboardPage.setUserHighlight(userRow);
    }
  } catch (err) {
    console.error("[leaderboard]", err);
    leaderboardPage.setStatus("error");
  }
}

const leaderboardPage = createLeaderboardPage(main, {
  authController,
  onClose: () => leaderboardPage.hide(),
  // Refresh button bypasses the 5-min cache — user explicitly asked.
  onRefresh: () => void refreshLeaderboard(true),
  onError: (err) => console.error("[auth]", err),
  // F-078 — nickname inline editor. Wired only when client + user
  // present (i.e. online + signed in). The chip's edit button is
  // hidden in any other state.
  ...(supabaseClient
    ? {
        onNicknameSave: async (nickname: string) => {
          const user = authController.getUser();
          if (!user) return { ok: false, reason: "not_signed_in" };
          const result = await updateNickname(
            supabaseClient,
            user.id,
            nickname,
          );
          if (result.ok) {
            // F-082 — push the saved nickname onto the auth controller so
            // the submit dialog / profile chip / any other consumer sees
            // the updated displayName immediately (no reload required).
            authController.setNickname(result.nickname ?? null);
            // Cache invalidate so the leaderboard re-fetches the new
            // display_name on the next open.
            onlineStore?.invalidateCache();
            void refreshLeaderboard(true);
            return { ok: true, nickname: result.nickname };
          }
          return { ok: false, reason: result.reason };
        },
      }
    : {}),
});

const submitDialog = createScoreSubmitDialog(main, {
  authController,
  store: onlineStore,
  onSubmitted: (rank) => {
    leaderboardPage.show();
    void refreshLeaderboard();
    void rank;
  },
  onError: (err) => console.error("[submit]", err),
});

// Sync the profile row right after Google sign-in so the leaderboard
// has the up-to-date name + avatar before the user submits anything.
// F-082 — also fetch any user-set nickname back onto the auth controller
// so the displayName seen across the UI matches what the leaderboard
// shows (no Google-vs-nickname mismatch on the submit dialog).
{
  let nicknameLoadedFor: string | null = null;
  authController.subscribe((user) => {
    if (!user || !supabaseClient) {
      nicknameLoadedFor = null;
      return;
    }
    void syncProfile(supabaseClient, user).catch((err) =>
      console.error("[profile-sync]", err),
    );
    if (nicknameLoadedFor === user.id) return; // already fetched this session
    nicknameLoadedFor = user.id;
    void supabaseClient
      .from("profiles")
      .select("display_name")
      .eq("id", user.id)
      .maybeSingle()
      .then(({ data }) => {
        const saved = (data?.display_name ?? "").trim();
        if (saved && saved !== user.displayName) {
          authController.setNickname(saved);
        }
      });
  });
}

function openLeaderboard(): void {
  leaderboardPage.show();
  void refreshLeaderboard();
}

// Open leaderboard via 'L' hotkey (desktop) — easy keyboard discoverability.
window.addEventListener("keydown", (e) => {
  if (e.key === "l" || e.key === "L") {
    if (e.target instanceof HTMLElement && e.target.tagName === "BUTTON") return;
    openLeaderboard();
  }
});

// F-075 — score-overlay 자체가 leaderboard 진입점. 게임 화면에는 별도
// 버튼 없음 — UI 가 깨끗해진다.
scoreOverlay.element.addEventListener("click", openLeaderboard);
scoreOverlay.element.addEventListener("keydown", (e) => {
  if (e.key === "Enter" || e.key === " ") {
    e.preventDefault();
    openLeaderboard();
  }
});

// Prompt the submission dialog only when (a) we have an online store
// configured AND (b) the run is meaningful (star forged or new high
// score). Repeat losses below the local high don't pester the player.
function maybePromptSubmit(
  snapshot: ReturnType<typeof score.snapshot>,
  starForged: boolean,
  force = false,
): void {
  if (!onlineStore) return;
  if (snapshot.current <= 0) return;
  // Auto-flow only prompts on a meaningful run (star or new high). The
  // explicit 🏆 등록 button (F-076) bypasses with force=true.
  if (!force && !starForged && snapshot.current <= snapshot.highScore) return;
  const durationMs = Math.max(30_000, Date.now() - runStartedAt.current);
  // F-086 — coerce peakTier to be consistent with starForged so the
  // server's sanity check passes (star_forged ⇔ peak_tier === 8).
  const peakTier = starForged
    ? 8
    : Math.max(0, Math.min(7, peakTierThisRun));
  submitDialog.prompt({
    userId: authController.getUser()?.id ?? "anonymous",
    score: snapshot.current,
    merges: snapshot.merges,
    durationMs,
    starForged,
    peakTier,
  });
}

void pauseBadge;

// Earth's emotion driver — reflects ammo + biggest in-flight tier so
// the player feels rising tension. Thresholds intentionally low so
// emotions shift through several states across a normal run rather
// than staying stuck on calm.
function syncEarthEmotion(): void {
  if (runController.isGameOver()) {
    earth.setEmotion("scared");
    return;
  }
  const a = ammo.state();
  const ratio = a.remaining / Math.max(1, a.total);
  const maxTier = sim.planets.reduce(
    (m, p) => Math.max(m, p.tier.index),
    0,
  );
  // Order matters — higher-priority states win.
  if (maxTier >= 8 || (ratio < 0.15 && maxTier >= 4)) {
    earth.setEmotion("scared");
  } else if (maxTier >= 6 || ratio < 0.25) {
    earth.setEmotion("worried");
  } else if (maxTier >= 3 || ratio < 0.55) {
    earth.setEmotion("nervous");
  } else if (ratio < 0.90 || maxTier >= 1) {
    earth.setEmotion("happy");
  } else {
    earth.setEmotion("calm");
  }
}

// 7. Input =================================================================
const PULL_VISUAL_SCALE = 1.6; // world units per normalized power
const slingshot = createSlingshot(canvas);
attachTouchGuard(canvas);

slingshot.on("drag", (aim) => {
  if (!aim.active || pause.isPaused() || runController.isGameOver()) return;
  if (!cooldown.isReady()) return;

  // Visual: pull held planet back, show power meter, draw trajectory.
  const pullX = aim.direction.x * aim.power * PULL_VISUAL_SCALE;
  const pullY = -aim.direction.y * aim.power * PULL_VISUAL_SCALE;
  launcher.setPullOffset({ x: pullX, y: pullY });
  powerMeter.setVisible(true);
  powerMeter.setPower(aim.power);

  if (aim.power > 0.04) {
    // Tame the impulse so meteors don't fly past Earth — gravity does
    // most of the work guiding them in.
    const impulse = computeLaunchImpulse(
      aim.power * settingsStore.current().sensitivity,
    ) * 0.55;
    // Pull-back semantic — drag in OPPOSITE of launch direction (Angry
    // Birds style). To launch right toward Earth, drag the planet LEFT.
    const velocity = {
      x: aim.direction.x * impulse,
      y: -aim.direction.y * impulse,
      z: 0,
    };
    const samples = sampleTrajectory({
      origin: launcher.origin,
      velocity,
      well: sim.well,
      steps: 32,
      dt: 0.07,
      maxRadius: 30,
    });
    trajectory.setPoints(samples);
    trajectory.setVisible(true);
  } else {
    trajectory.setVisible(false);
  }
});

slingshot.on("release", (aim) => {
  trajectory.setVisible(false);
  powerMeter.setVisible(false);
  launcher.setPullOffset({ x: 0, y: 0 });

  if (pause.isPaused() || runController.isGameOver()) return;
  if (aim.power < 0.05) return;
  if (ammo.isEmpty()) return;
  if (!cooldown.tryArm()) return;
  ammo.consume();

  const tierIndex = queue.advance();
  // Match the trajectory-preview impulse (× 0.55) so the dotted line
  // truly predicts where the meteor goes.
  const impulse = computeLaunchImpulse(
    aim.power * settingsStore.current().sensitivity,
  ) * 0.55;
  // Pull-back semantic — match the drag handler.
  const planet = sim.spawnPlanet({
    tierIndex,
    position: { ...launcher.origin },
    velocity: {
      x: aim.direction.x * impulse,
      y: -aim.direction.y * impulse,
      z: 0,
    },
  });
  trails.track(planet);
  audio.play("launch", { intensity: aim.power });
  // First time the player commits a tier into play, light it up on
  // both the goal-pill peak counter and the bottom tier-ladder chip.
  goalPill.setPeakTier(planet.tier.index);
  tierLadderPanel.setPeakTier(planet.tier.index);

  // Muzzle flash — bright spark burst at the launch zone for the
  // "round leaves the chamber" punctuation.
  particles.spawnSpark({
    position: { ...launcher.origin },
    color: planet.tier.color,
    intensity: 1.4,
  });

  // Reload sequence — preview vanishes briefly, then drops the next
  // tier in. Player visually understands "ammo cycled".
  launcher.reload(queue.peek()[0] ?? 0);
  queueStrip.refresh();
});

slingshot.on("cancel", () => {
  trajectory.setVisible(false);
  powerMeter.setVisible(false);
  launcher.setPullOffset({ x: 0, y: 0 });
});

// Keyboard a11y — Esc pauses, Enter restarts on game-over screen.
window.addEventListener("keydown", (event) => {
  if (event.code === "Escape") {
    pause.toggle();
  }
  if (
    event.code === "Enter" &&
    runController.isGameOver()
  ) {
    gameOverOverlay.element.querySelector<HTMLButtonElement>(
      '[data-testid="gameover-restart"]',
    )?.click();
  }
});

// Tutorial — show on first visit
if (tutorial.shouldShow()) {
  tutorial.show();
  tutorialOverlay.show();
}

// Responsive resize
attachResponsive({
  camera: handles.camera,
  renderer: handles.renderer,
  collapsiblePanels: [queueStrip.element],
});

// F-092 — 우하단 버전 뱃지. tap 시 토스트에 audio 시스템 진단 함께 표시
// (F-091 hotfix#3 — iPad 사운드 무음 디버깅용).
