// F-091 hotfix#3 — explicit "tap to enable sound" pill. 자동 unlock 이
// iPad 에서 실패한 경우의 보장 path. ctx 가 'running' 으로 확인되면
// 자동으로 사라짐.
mountAudioPrompt({ audio });

// 8. Game loop =============================================================
let lastT = performance.now();
function tick(now: number): void {
  const dt = Math.min((now - lastT) / 1000, 1 / 30);
  lastT = now;

  if (!pause.isPaused() && !runController.isGameOver()) {
    sim.step(dt);

    // Constrain every meteor to the camera-facing playfield plane (z=0).
    // Without this they orbit around behind Earth and disappear from view.
    for (const p of sim.planets) {
      p.body.position.z = 0;
      p.body.velocity.z = 0;
    }

    // Resolve merges → score, audio, particles, combo, shake, popups
    const candidates = sim.drainMergeCandidates();
    if (candidates.length > 0) {
      // Snapshot the merge centroids BEFORE resolution removes the bodies.
      const mergeCenters = candidates.map((c) => ({
        x: (c.a.body.position.x + c.b.body.position.x) / 2,
        y: (c.a.body.position.y + c.b.body.position.y) / 2,
        z: (c.a.body.position.z + c.b.body.position.z) / 2,
        tierIndex: c.tierIndex,
      }));
      // Forget trails of the planets about to be consumed by the merge.
      for (const c of candidates) {
        trails.forget(c.a);
        trails.forget(c.b);
      }
      const result = resolveMerges(sim, candidates);
      // Combo: each merge in this batch extends the chain. The first
      // batch-internal merge gets fresh state; subsequent batch entries
      // also extend (effectively "multi-merge in one frame").
      let multiplier = 1;
      for (let i = 0; i < result.ascensions + result.topTierBursts; i += 1) {
        multiplier = combo.registerMerge(now);
      }
      if (result.scoreDelta > 0) {
        const boosted = Math.round(result.scoreDelta * multiplier);
        score.add(boosted, result.ascensions + result.topTierBursts);
        // Floating "+points" popup at the first merge center — tinted
        // by the resulting tier color.
        const center = mergeCenters[0];
        if (center) {
          const tierColor =
            result.spawned[0]?.tier.color ?? 0xffffff;
          scorePopups.spawn({
            position: { x: center.x, y: center.y, z: center.z },
            points: boosted,
            color: tierColor,
            ...(multiplier > 1 ? { multiplier } : {}),
          });
        }
      }
      // Camera shake — intensity scales with the biggest merge tier.
      const peakTier = mergeCenters.reduce(
        (m, c) => Math.max(m, c.tierIndex),
        0,
      );
      cameraShake.kick(0.25 + peakTier * 0.08);
      for (const planet of result.spawned) {
        const intensity = Math.min(1, planet.tier.index / 6);
        particles.spawn({
          position: {
            x: planet.body.position.x,
            y: planet.body.position.y,
            z: planet.body.position.z,
          },
          color: planet.tier.color,
        });
        audio.play("merge", { intensity });
        trails.track(planet);
        goalPill.setPeakTier(planet.tier.index);
        tierLadderPanel.setPeakTier(planet.tier.index);
        if (planet.tier.index > peakTierThisRun) {
          peakTierThisRun = planet.tier.index;
        }
        // Tame the post-merge spawn impulse for ~250ms so the new
        // (bigger) body doesn't spring wildly when cannon-es resolves
        // its overlap with the surrounding stack.
        mergeSettle.register(planet.id, planet.body, planet.tier.index, now);
      }
    }
    combo.tick(now);
    mergeSettle.tick(now);

    // Victory — first STAR forged unlocks endless mode. Show the
    // explicit "🌟 STAR FORGED" overlay so the goal-met moment is
    // unambiguous; player clicks Continue to keep playing for score.
    const hasStar = sim.planets.some((p) => isStarTier(p.tier.index));
    if (hasStar && !endlessMode && !runController.isGameOver()) {
      endlessMode = true;
      const snapshot = score.snapshot();
      if (snapshot.current > snapshot.highScore) {
        score.setHighScore(snapshot.current);
        highScoreStore.save(snapshot.current);
      }
      audio.play("merge", { intensity: 1 });
      cameraShake.kick(1.4);
      for (let burst = 0; burst < 14; burst += 1) {
        particles.spawn({
          position: {
            x: EARTH_POSITION.x + (Math.random() - 0.5) * earth.radius,
            y: EARTH_POSITION.y + (Math.random() - 0.5) * earth.radius,
            z: EARTH_POSITION.z,
          },
          color: 0xffe066,
        });
      }
      // Restore Earth integrity — clean slate for endless run.
      ozone.reset();
      earth.setEmotion("celebrate");
      gameOverOverlay.show(score.snapshot(), "star-forged");
      maybePromptSubmit(score.snapshot(), true);
    }

    // Per-frame ozone + escape update. Build snapshots once with each
    // meteor's distance from Earth, speed, tier.
    const meteorSnapshots = sim.planets.map((p) => {
      const dx = p.body.position.x - EARTH_POSITION.x;
      const dy = p.body.position.y - EARTH_POSITION.y;
      const dz = p.body.position.z - EARTH_POSITION.z;
      return {
        id: p.id,
        distance: Math.hypot(dx, dy, dz),
        speed: p.body.velocity.length(),
        tierIndex: p.tier.index,
      };
    });

    // Escape first — meteors that flew off-screen are removed from
    // the sim BEFORE the ozone breach detector runs, so they can't
    // double-fire as both "escape" and "breach".
    const escapedIds = escape.update(meteorSnapshots);
    if (escapedIds.length > 0) {
      const escapedSet = new Set(escapedIds);
      for (const id of escapedIds) {
        const p = sim.planets.find((pl) => pl.id === id);
        if (p) sim.removePlanet(p);
      }
      // Drop their snapshots so ozone doesn't see them this frame.
      for (let i = meteorSnapshots.length - 1; i >= 0; i -= 1) {
        if (escapedSet.has(meteorSnapshots[i]!.id)) {
          meteorSnapshots.splice(i, 1);
        }
      }
    }

    ozone.update(dt, meteorSnapshots);

    // Drive the ring's danger gauge — closer-to-breach meteors raise
    // the warning hue. We use the count of dwelling meteors as a
    // simple proxy: any in-flight dwell shows yellow; multiple show
    // full red.
    const dwellingIds = ozone.dwellingMeteorIds();
    ozoneRing.setDanger(Math.min(1, dwellingIds.length * 0.55));

    // Per-meteor "DANGER" warning label on every meteor that's
    // currently dwelling outside the ozone — the explicit cue that
    // this meteor is the one counting down to a breach.
    const idSet = new Set(dwellingIds);
    const dwellingMeteors = sim.planets
      .filter((p) => idSet.has(p.id))
      .map((p) => ({
        id: p.id,
        position: {
          x: p.body.position.x,
          y: p.body.position.y,
          z: p.body.position.z,
        },
      }));
    breachWarning.setDwellingMeteors(dwellingMeteors, now, {
      width: handles.renderer.domElement.clientWidth,
      height: handles.renderer.domElement.clientHeight,
    });

    // Game-over (loss) — Earth structural integrity collapsed.
    if (ozone.isCollapsed() && !runController.isGameOver()) {
      const snapshot = score.snapshot();
      if (snapshot.current > snapshot.highScore) {
        score.setHighScore(snapshot.current);
        highScoreStore.save(snapshot.current);
      } else {
        highScoreStore.save(snapshot.highScore);
      }
      leaderboard.record({
        score: snapshot.current,
        merges: snapshot.merges,
        iso: todayUtcIso(),
      });
      achievements.evaluate({ score: snapshot, gameOver: true });
      audio.play("gameover");
      runController.endRun();
      gameOverOverlay.show(score.snapshot(), "shattered");
      launcher.setVisible(false);
      maybePromptSubmit(score.snapshot(), false);
    }
  }

  earth.tick(dt);
  moon.tick(dt);
  syncEarthEmotion();
  starfield.tick(dt);
  launcherPreview.tick(now);
  trails.tick();
  particles.tick(now);
  ozoneRing.tick(dt);
  cameraShake.tick(dt);
  comboBadge.tick(now);
  scorePopups.tick(now, {
    width: handles.renderer.domElement.clientWidth,
    height: handles.renderer.domElement.clientHeight,
  });
  // Backdrop is now a flat plane — no rotation applied.
  handles.renderer.render(handles.scene, handles.camera);
  requestAnimationFrame(tick);
}

requestAnimationFrame(tick);

// Test seam (F-036) — minimal hook for the gameplay smoke. Production
// builds tree-shake this when `import.meta.env.PROD` is true via Vite,
// but happy to keep it lightweight in dev.
declare global {
  interface Window {
    __cosmic?: {
      planets(): number;
      score(): { current: number; high: number; merges: number };
      ammo(): { remaining: number; total: number };
      gameOver(): boolean;
    };
  }
}
window.__cosmic = {
  planets: () => sim.planets.length,
  score: () => {
    const s = score.snapshot();
    return { current: s.current, high: s.highScore, merges: s.merges };
  },
  ammo: () => ammo.state(),
  gameOver: () => runController.isGameOver(),
};

// =========================================================================
// Tutorial overlay — minimal inline mount. Decoupled from src/ui/tutorial.ts
// (which owns state) so the visual layer can stay light.
// =========================================================================
interface TutorialOverlayHandle {
  show(): void;
}

interface TutorialOverlayOptions {
  /** Fired the first time render() actually displays the card. */
  onShown?: () => void;
  /** Fired when the card hides (next-end OR skip). */
  onDismissed?: () => void;
}

function mountTutorialOverlay(
  host: HTMLElement,
  controller: ReturnType<typeof createTutorialController>,
  options: TutorialOverlayOptions = {},
): TutorialOverlayHandle {
  const totalSteps = TUTORIAL_STEPS.length;
  const wrap = document.createElement("div");
  wrap.dataset["testid"] = "tutorial-overlay";
  wrap.className =
    "pointer-events-auto absolute inset-x-0 bottom-32 mx-auto flex w-[min(440px,92vw)] flex-col gap-2 rounded-2xl bg-black/75 p-4 text-slate-100 shadow-2xl ring-1 ring-white/10 backdrop-blur-md transition-opacity duration-200 sm:bottom-40";
  wrap.style.display = "none";

  const header = document.createElement("div");
  header.className = "flex items-baseline justify-between gap-3";

  const title = document.createElement("div");
  title.dataset["testid"] = "tutorial-title";
  title.className = "font-display text-base text-cosmic-star sm:text-lg";

  const stepCount = document.createElement("div");
  stepCount.dataset["testid"] = "tutorial-step-count";
  stepCount.className = "text-[10px] tracking-widest text-slate-400 sm:text-xs";

  header.append(title, stepCount);

  const body = document.createElement("p");
  body.className = "text-sm leading-snug text-slate-200";

  const actions = document.createElement("div");
  actions.className = "flex justify-end gap-2 pt-2";
  const skip = document.createElement("button");
  skip.type = "button";
  skip.dataset["testid"] = "tutorial-skip";
  skip.textContent = t("tutorial.skip");
  skip.className =
    "rounded-md px-3 py-1 text-xs text-slate-300 hover:bg-white/10";
  const next = document.createElement("button");
  next.type = "button";
  next.dataset["testid"] = "tutorial-next";
  next.textContent = t("tutorial.next");
  next.className =
    "rounded-md bg-cosmic-glow/80 px-4 py-1 text-xs font-bold text-cosmic-deep hover:bg-cosmic-glow";
  actions.append(skip, next);

  wrap.append(header, body, actions);
  host.appendChild(wrap);

  const findStepIndex = (stepId: string | undefined): number => {
    if (!stepId) return -1;
    return TUTORIAL_STEPS.findIndex((s) => s.id === stepId);
  };

  // F-079 — track whether the card is currently shown, so onShown /
  // onDismissed only fire on actual transitions (idempotent).
  let visible = false;
  const setVisible = (next: boolean): void => {
    if (next === visible) return;
    visible = next;
    wrap.style.display = next ? "flex" : "none";
    if (next) options.onShown?.();
    else options.onDismissed?.();
  };

  const render = (): void => {
    const step = controller.currentStep();
    if (!step) {
      setVisible(false);
      return;
    }
    const idx = findStepIndex(step.id);
    title.textContent = step.title;
    body.textContent = step.body;
    stepCount.textContent = idx >= 0 ? `${idx + 1} / ${totalSteps}` : "";
    // Last step → CTA reads "시작!" instead of "다음" so the player
    // knows clicking it ends the tutorial and starts the game.
    next.textContent =
      idx === totalSteps - 1 ? t("tutorial.start") : t("tutorial.next");
    setVisible(true);
  };

  next.addEventListener("click", () => {
    if (controller.next() === null) {
      setVisible(false);
    } else {
      render();
    }
  });
  skip.addEventListener("click", () => {
    controller.skip();
    setVisible(false);
  });

  return { show: render };
}
