/**
 * F-091 hotfix#3 — explicit "tap to enable sound" prompt for iOS.
 *
 * 자동 gesture-unlock 이 어떤 이유로든 실패해도 보장 path 로 동작. iOS
 * 가 절대 인정하는 click handler 안에서 audio.unlockNow() → ctx 생성
 * + resume + audible test tone 재생. 성공시 fade out.
 *
 * 사용자가 화면을 탭하기 전엔 화면 상단 중앙에 small pill 로 표시.
 * audio 가 이미 'running' 이면 즉시 self-detach.
 */

import type { AudioSystem } from "../audio/system.ts";

export interface AudioPromptOptions {
  audio: AudioSystem;
  root?: HTMLElement;
  /** Test seam — string literal localized label. */
  label?: string;
}

export function mountAudioPrompt(opts: AudioPromptOptions): {
  detach: () => void;
} {
  const root = opts.root ?? document.body;
  const label = opts.label ?? "🔊 효과음 활성화";

  // 이미 running 이면 prompt 띄우지 않음 — desktop 등.
  if (opts.audio.diagnostics().ctxState === "running") {
    return { detach: () => undefined };
  }

  const button = document.createElement("button");
  button.type = "button";
  button.setAttribute("data-testid", "audio-prompt");
  button.setAttribute("aria-label", "Enable sound effects");
  button.textContent = label;
  button.className = [
    "fixed",
    "top-3",
    "left-1/2",
    "-translate-x-1/2",
    "z-50",
    "px-4",
    "py-2",
    "rounded-full",
    "bg-cosmic-glow/90",
    "text-white",
    "text-sm",
    "font-display",
    "font-medium",
    "shadow-lg",
    "ring-2",
    "ring-cosmic-glow/40",
    "backdrop-blur",
    "transition",
    "hover:bg-cosmic-glow",
    "active:scale-95",
    "animate-pulse",
    "select-none",
  ].join(" ");

  let removed = false;
  const detach = (): void => {
    if (removed) return;
    removed = true;
    button.remove();
  };

  button.addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    opts.audio.unlockNow();
    // diagnostics 가 'running' 으로 갱신될 때까지 잠깐 기다린 후 사라짐
    window.setTimeout(() => {
      const state = opts.audio.diagnostics().ctxState;
      if (state === "running") {
        button.classList.add("opacity-0", "pointer-events-none");
        window.setTimeout(detach, 300);
      }
    }, 100);
  });

  // 게임 화면 탭/슬링샷으로 자동 unlock 됐을 가능성도 있음 — 짧은 주기로
  // 폴링해 'running' 감지되면 prompt 자동 사라짐.
  const poll = window.setInterval(() => {
    if (removed) {
      window.clearInterval(poll);
      return;
    }
    if (opts.audio.diagnostics().ctxState === "running") {
      window.clearInterval(poll);
      button.classList.add("opacity-0", "pointer-events-none");
      window.setTimeout(detach, 300);
    }
  }, 500);

  root.appendChild(button);

  return {
    detach: () => {
      window.clearInterval(poll);
      detach();
    },
  };
}
